**Trie node**: each node holds a `children` map (char → next node) and an `isEnd` flag. Insertion walks/creates nodes; search walks and checks `isEnd`; `startsWith` walks only.

```javascript
function runOps(ops) {
  function makeNode() { return { children: {}, isEnd: false }; }
  const root = makeNode();
  function insert(word) {
    let cur = root;
    for (const c of word) {
      if (!cur.children[c]) cur.children[c] = makeNode();
      cur = cur.children[c];
    }
    cur.isEnd = true;
    return null;
  }
  function walk(word) {
    let cur = root;
    for (const c of word) {
      if (!cur.children[c]) return null;
      cur = cur.children[c];
    }
    return cur;
  }
  function search(word) {
    const node = walk(word);
    return !!(node && node.isEnd);
  }
  function startsWith(pre) {
    return walk(pre) !== null;
  }
  return ops.map(([op, arg]) => {
    if (op === 'insert') return insert(arg);
    if (op === 'search') return search(arg);
    return startsWith(arg);
  });
