**Idea — trie + DFS with pruning**: Build a trie of all target words; each terminal node stores the full word. DFS from every cell; at each step, descend the trie; on `isEnd` push the word and clear `isEnd` (so we don't double-add). Mark visited via `'#'` swap; restore on backtrack.

```javascript
function findWordsInBoard(board, words) {
  const root = { children: {}, word: null };
  for (const w of words) {
    let cur = root;
    for (const c of w) {
      if (!cur.children[c]) cur.children[c] = { children: {}, word: null };
      cur = cur.children[c];
    }
    cur.word = w;
  }
  const rows = board.length, cols = board[0].length;
  const found = [];
  function dfs(r, c, node) {
    const ch = board[r][c];
    const next = node.children[ch];
    if (!next) return;
    if (next.word !== null) {
      found.push(next.word);
      next.word = null;
    }
    board[r][c] = '#';
    const dirs = [[-1,0],[1,0],[0,-1],[0,1]];
    for (const [dr, dc] of dirs) {
      const nr = r + dr, nc = c + dc;
      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && board[nr][nc] !== '#') {
        dfs(nr, nc, next);
      }
    }
    board[r][c] = ch;
  }
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) dfs(r, c, root);
  }
  found.sort();
  return found;
}
```

**Time**: O(R*C * 4^L) worst case. **Space**: O(total word chars).

Clearing `next.word` after a hit prevents double counting and prunes future searches for the same word.

