      if (!cur.children[c]) cur.children[c] = makeNode();
      cur = cur.children[c];
    }
    cur.isEnd = true;
  }
  const buf = [];
  const out = [];
  for (const ch of letters) {
    buf.push(ch);
    let cur = root;
    let found = false;
    for (let i = buf.length - 1; i >= 0; i--) {
      const c = buf[i];
      if (!cur.children[c]) break;
      cur = cur.children[c];
      if (cur.isEnd) { found = true; break; }
