**Idea — set membership for every prefix**: A word `w` is buildable iff every prefix `w[0..i-1]` for `i = 1..|w|-1` is also in the dictionary. Put `words` into a Set, iterate, check prefixes.

```javascript
function longestWord(words) {
  const set = new Set(words);
  let best = '';
  for (const w of words) {
    if (w.length < best.length) continue;
    if (w.length === best.length && w >= best) continue;
    let ok = true;
    for (let i = 1; i < w.length; i++) {
      if (!set.has(w.slice(0, i))) { ok = false; break; }
    }
    if (ok) best = w;
  }
  return best;
}
